var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SUPV_VARUNA_NPC_NULL","text":{"KOREA":"조심해서 옮겨! 거대한 녀석일수록 내부에 뭐가 있을지 모른다!","JPN":"気をつけて運べ！　巨大なやつほど、中に何がいるかわからないぞ！","ENG":"Be careful moving that! The bigger it is, there's no knowing what else is inside!","TWN":"搬的時候小心點！這麼大一個，裡面不知道是什麼！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUPV_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"SUPV_VARUNA_NPC_NULL","text":{"KOREA":"이렇게 큰 녀석은 살면서 처음이군.","JPN":"こんなにデカいやつは生まれて初めて見るな。","ENG":"I've never seen a C.O. this huge before.","TWN":"……我還是第一次見到這麼大的。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUPV_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SUPV_VARUNA_NPC_NULL","text":{"KOREA":"외피가 워낙 단단해야지…… 절단 작업만 해도 몇 달은 걸리겠어.","JPN":"外皮が固すぎる……切断作業だけでも何カ月はかかりそうだ。","ENG":"Its outer skin is so thick... just cutting it will take months.","TWN":"表皮非常堅硬……光是切割作業就要花上幾個月吧……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUPV_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SUPV_VARUNA_NPC_NULL","text":{"KOREA":"음? 여긴 출입 금지 구역입니다.","JPN":"ん？　こちらは出入り禁止区域です。","ENG":"Hmm? This is a restricted area.","TWN":"嗯？這裡是禁止出入的區域。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUPV_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SUPV_VARUNA_NPC_NULL","text":{"KOREA":"침식체의 잔해를 수거하고 있으니 용무가 없으시다면 돌아가 주세요.","JPN":"侵食体の残骸を回収してますので、用がないなら帰ってください。","ENG":"We are currently collecting the remains of the C.O., so if you have no business here, please leave.","TWN":"我們正在回收侵蝕體的殘骸，如果沒有其他事情，請回去吧。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUPV_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"……이런 곳에 있었던 건가.","JPN":"……こんなところにいたのか。","ENG":"...Was it here all this time?","TWN":"……在這種地方嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUPV_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SUPV_VARUNA_NPC_NULL","text":{"KOREA":"이봐요! 여긴 출입 금지 구역이라고……!","JPN":"あのですね！　ここは出入り禁止区域だと……！","ENG":"Hey! I told you, this place is off–","TWN":"喂！這裡禁止出入……！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUPV_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"SUPV_VARUNA_NPC_NULL","text":{"KOREA":"커허억…… 끄르륵…….","JPN":"グハッ……グググッ……","ENG":"Kuh...! Errrrgh...","TWN":"咳……咳咳……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUPV_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"지금은 <color=#ffd34c>대환류</color>라고 부르는 미제 사건.","JPN":"今は<color=#ffd34c>大還流</color>と呼ばれる未解決事件。","ENG":"The unsolved case, now called the <color=#ffd34c>Great Gyre</color>.","TWN":"如今被稱為<color=#ffd34c>大環流</color>的未解案件。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"고고학부장은 신적인 존재를 담을 그릇을 준비하지 못한 탓에 의식이 실패했다고 결론 내렸지만.","JPN":"考古学部長は神的な存在を宿す器を用意できなかったせいで儀式が失敗したのだと結論づけたが、","ENG":"The Dean of Archeology concluded that the ritual had failed due to not having a vessel to contain godlike creatures.","TWN":"透過考古學院長得出結論，儀式失敗是因為尚未準備好容納神的器皿。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"엄밀히 말하면 의식은 실패한 것이 아니었어.","JPN":"厳密に言うと、儀式は失敗したわけではなかったのだ。","ENG":"However, the ritual was not a failure, strictly speaking.","TWN":"但嚴格來說，儀式並沒有失敗。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"이 세계에 존재하지 않는, 형용할 수 없는 어떠한 존재는 구 관리국의 함선과 승무원들을 매개로 삼았지.","JPN":"この世界に存在しない、言葉では表せないとある存在は旧管理局の艦船と乗務員を媒介とした。","ENG":"An indescribable being that does not exist in this world used the Old Administration's ship and crew as a medium.","TWN":"某種在這個世界上無法形容的存在，它以舊管理局艦船和隊員為媒介。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그 결과, 정보 왜곡이 일어나 그들의 존재가 말소되어 버렸던 거야.","JPN":"その結果、情報歪曲が生じ彼らの存在が抹消されてしまったのだ。","ENG":"As a result, information was distorted and their existence was erased.","TWN":"結果，相關的資訊被扭曲，隊員的存在被抹除。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"하지만 탐식자는 어째서 로터스의 모래폭풍을 방치해둔 것이지?","JPN":"だが貪食者はどうしてロータスの砂嵐を放置したのか？","ENG":"Then why did the Devourer neglect Lotus' sandstorm?","TWN":"但是，貪食者為什麼會放任洛德斯的沙塵暴不管？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"혹시, 알아차리지 못한 건가?","JPN":"もしかして、気付いていないのか？","ENG":"Did she... not notice?","TWN":"難道，是沒有察覺到嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"아니. 그럴 리 없어.","JPN":"いや。そのはずはない。","ENG":"No. That is impossible.","TWN":"不，那是不可能的。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"회원이 휘말린 의식이야. 학회가 모를 리가 없지.","JPN":"会員が巻き込まれた儀式だ。学会が知らないわけがない。","ENG":"The Society members were involved in the ritual. The Society was fully aware.","TWN":"這是學會干預的儀式，他們不可能不知道。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"미상의 파리목 생물 발생.","JPN":"未詳のハエ目生物発生。","ENG":"An occurrence of an unknown fly species.","TWN":"未知的雙翅目的生物。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"역겨운 악취.","JPN":"耐えられない悪臭。","ENG":"Then vile smell.","TWN":"還有令人作嘔的惡臭。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"가아그셰블라의 클리파 허수 에너지를 오염시켜 다른 타입의 신성으로 변환시킨 건가.\xA0","JPN":"ガアグシェブラのクリファ虚数エネルギーを汚染させ、他のタイプの神聖に変換させたわけか。\xA0","ENG":"Has it polluted Gha'agsheblah's Qlipha Imaginary Energy and transformed it into a different type of divinity?\xA0","TWN":"是它污染加格舍夫拉的逆卡巴拉虛數能量，並轉化為其他類型的神聖能量嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"이건…… <color=#ffd34c>검은 죽음</color>의 안배로군.\xA0","JPN":"これは……<color=#ffd34c>黒い死</color>が用意したことか。","ENG":"This is... the arrangement of the <color=#ffd34c>Black Death</color>.\xA0","TWN":"這是……<color=#ffd34c>黑死</color>的手法。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그릇의 핵은 이미 변질되었다.\xA0","JPN":"器の核はすでに変質した。\xA0","ENG":"The vessel's core has already spoiled.\xA0","TWN":"器皿的核心已變質。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"파편을 회수해도 어머니께 도움이 되진 않겠지.","JPN":"破片を回収してもお母さんの役には立たないだろう。","ENG":"Even if I retrieve the Fragment, it will be of no use to Mother.","TWN":"即使收回碎片，對母親也沒幫助。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"하지만…….\xA0\xA0","JPN":"だが……\xA0\xA0","ENG":"However...\xA0\xA0","TWN":"可是……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"사체는 챙겨서 돌아간다.","JPN":"死体は持って帰る。","ENG":"I will take back the corpse.","TWN":"屍體我會帶回去。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"지금 당장 파편을 흡수할 수 없지만, 학회에게 고스란히 넘겨줄 수는 없어.","JPN":"今すぐ破片を吸収することはできないが、学会に渡すわけにはいかない。","ENG":"Even if the Fragment cannot be absorbed right now, I cannot allow the Society to obtain it.","TWN":"雖然無法立即吸收碎片，但也不能就這樣讓給學會。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"이 일은 반드시 기억해 두겠다.","JPN":"これで済むとは思わないことだ。","ENG":"I shall remember what happened here.","TWN":"這件事我記住了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"불순한 의도를 가지고 어머니의 앞을 가로막은 것이라면…….","JPN":"不純な意図でお母さんの前に立ちはだかったのであれば……","ENG":"If you had malintent to block Mother's path...","TWN":"如果意圖不軌地擋在母親面前……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"반드시 대가를 치를 것이다.","JPN":"必ず対価を支払ってもらう。","ENG":"You will pay the price for doing so.","TWN":"我一定會讓你付出代價的。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"<color=#ffd34c>벨제부브</color>.","JPN":"<color=#ffd34c>ベルゼブブ</color>。","ENG":"<color=#ffd34c>Beelzebub</color>.","TWN":"<color=#ffd34c>別西卜</color>。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};